import { Component, OnInit } from '@angular/core';
import { Router } from '@angular/router';
import { FormBuilder, FormGroup, Validators } from '@angular/forms';
import { CartService } from '../services/cart.service';
import { OrderService } from '../services/order.service';
import { AuthService } from '../services/auth.service';
import { CartItem } from '../models/models';

@Component({
  selector: 'app-cart',
  templateUrl: './cart.component.html',
  styleUrls: ['./cart.component.css']
})
export class CartComponent implements OnInit {
  cartItems: CartItem[] = [];
  loading = true;
  error = '';
  showCheckout = false;
  checkoutForm: FormGroup;
  subtotal = 0;
  shipping = 0;
  tax = 0;
  total = 0;

  constructor(
    private cartService: CartService,
    private orderService: OrderService,
    private authService: AuthService,
    private router: Router,
    private fb: FormBuilder
  ) {
    this.checkoutForm = this.fb.group({
      shippingAddress: ['', Validators.required],
      shippingCity: ['', Validators.required],
      shippingState: ['', Validators.required],
      shippingPincode: ['', [Validators.required, Validators.pattern('^[0-9]{6}$')]]
    });
  }

  ngOnInit() {
    if (!this.authService.isLoggedIn()) {
      this.router.navigate(['/login']);
      return;
    }
    this.loadCart();
  }

  loadCart() {
    this.loading = true;
    this.cartService.getCartItems().subscribe({
      next: (items) => {
        this.cartItems = items;
        this.calculateTotals();
        this.loading = false;
      },
      error: (error) => {
        this.error = error.error || 'Failed to load cart items';
        this.loading = false;
        console.error('Error loading cart:', error);
        
        if (error.status === 401) {
          this.authService.logout();
          this.router.navigate(['/login']);
        }
      }
    });
  }

  calculateTotals() {
    this.subtotal = this.cartItems.reduce((sum, item) => sum + (item.price * item.quantity), 0);
    this.shipping = this.subtotal > 999 ? 0 : 40;
    this.tax = this.subtotal * 0.18;
    this.total = this.subtotal + this.shipping + this.tax;
  }

  updateQuantity(item: CartItem, change: number) {
    const newQuantity = item.quantity + change;
    if (newQuantity < 1) {
      this.removeItem(item);
      return;
    }

    this.cartService.updateCartItem(item.id, newQuantity).subscribe({
      next: () => {
        item.quantity = newQuantity;
        this.calculateTotals();
        this.cartService.getCartCount();
      },
      error: (error) => {
        alert(error.error || 'Failed to update quantity');
      }
    });
  }

  removeItem(item: CartItem) {
    if (confirm('Are you sure you want to remove this item from cart?')) {
      this.cartService.removeFromCart(item.id).subscribe({
        next: () => {
          this.cartItems = this.cartItems.filter(i => i.id !== item.id);
          this.calculateTotals();
          this.cartService.getCartCount();
        },
        error: (error) => {
          alert(error.error || 'Failed to remove item');
        }
      });
    }
  }

  proceedToCheckout() {
    if (this.cartItems.length === 0) {
      alert('Your cart is empty');
      return;
    }
    this.showCheckout = true;
  }

  placeOrder() {
    if (this.checkoutForm.invalid) {
      return;
    }

    this.loading = true;
    this.orderService.createOrder(this.checkoutForm.value).subscribe({
      next: (response) => {
        this.loading = false;
        this.router.navigate(['/payment', response.orderId]);
      },
      error: (error) => {
        this.loading = false;
        alert(error.error?.error || 'Failed to place order');
      }
    });
  }

  continueShopping() {
    this.router.navigate(['/home']);
  }
}
